import Layout from '../components/Layout';
import AdminBookForm from '../components/AdminBookForm';
import LoadingState from '../components/LoadingState';
import { supabase } from '../lib/supabaseClient';
import { useState, useEffect } from 'react';
import { useRouter } from 'next/router';

export default function Admin() {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(false);
  const [recentBooks, setRecentBooks] = useState([]);
  const [fetchLoading, setFetchLoading] = useState(true);
  const [userRole, setUserRole] = useState(null);

  useEffect(() => {
    checkUser();
    fetchRecentBooks();
  }, []);

  async function checkUser() {
    const { data: { user } } = await supabase.auth.getUser();
    if (!user) {
      router.push('/login');
      return;
    }
    const { data: profile } = await supabase
      .from('profiles')
      .select('role')
      .eq('id', user.id)
      .single();
    
    if (profile?.role !== 'admin') {
      router.push('/books');
      return;
    }
    setUserRole('admin');
  }

  async function fetchRecentBooks() {
    setFetchLoading(true);
    try {
      const { data, error } = await supabase
        .from('books')
        .select('*')
        .order('created_at', { ascending: false })
        .limit(5);
      if (error) throw error;
      setRecentBooks(data || []);
    } catch (err) { console.error('Error:', err); }
    finally { setFetchLoading(false); }
  }

  async function handleSubmit(formData) {
    setLoading(true);
    try {
      const { error } = await supabase.from('books').insert([formData]);
      if (error) throw error;
      setSuccess(true);
      fetchRecentBooks();
      setTimeout(() => setSuccess(false), 3000);
    } catch (err) { alert('Access Denied or Error: ' + err.message); }
    finally { setLoading(false); }
  }

  async function handleDelete(id) {
    if (!confirm('Are you sure you want to delete this book?')) return;
    try {
      const { error } = await supabase.from('books').delete().eq('id', id);
      if (error) throw error;
      fetchRecentBooks();
    } catch (err) { alert('Delete Error: ' + err.message); }
  }

  if (!userRole) return <Layout><LoadingState message="Verifying admin credentials..." /></Layout>;

  return (
    <Layout>
      <div className="animate-fade-in-up">
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
          <h1 style={{ fontFamily: 'var(--font-body)', fontSize: '1.5rem', fontWeight: 700 }}>Admin Panel</h1>
          <span className="badge badge-available">Logged in as Admin</span>
        </div>

        <AdminBookForm onSubmit={handleSubmit} loading={loading} />

        {success && <div className="alert-success animate-fade-in" style={{ marginTop: '1rem', textAlign: 'center', maxWidth: 640, margin: '1rem auto 0' }} role="status">✓ Book saved to database!</div>}

        <div className="card-static" style={{ marginTop: '2rem' }}>
          <h3 style={{ fontFamily: 'var(--font-body)', fontSize: '1rem', fontWeight: 700, marginBottom: '1rem', color: 'var(--text-dark)' }}>Recently Added Books</h3>
          {fetchLoading ? (
            <LoadingState message="Fetching activity..." />
          ) : (
            <div className="table-wrap">
              <table className="table">
                <thead>
                  <tr>
                    <th>Title</th>
                    <th>Author</th>
                    <th>Status</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {recentBooks.map(book => {
                    const status = book.quantity > 2 ? 'available' : book.quantity > 0 ? 'low' : 'unavailable';
                    return (
                      <tr key={book.id}>
                        <td style={{ fontWeight: 600, color: 'var(--text-dark)' }}>{book.title}</td>
                        <td>{book.author}</td>
                        <td>
                          <span className={`badge badge-${status}`}>
                            <span className={`badge-dot badge-dot-${status === 'available' ? 'green' : status === 'low' ? 'orange' : 'red'}`} />
                            {status === 'available' ? 'Available' : status === 'low' ? 'Low Stock' : 'Unavailable'}
                          </span>
                        </td>
                        <td>
                          <button className="btn btn-ghost btn-sm" aria-label={`Delete ${book.title}`} onClick={() => handleDelete(book.id)} style={{ color: 'var(--red-500)' }}>
                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true"><polyline points="3 6 5 6 21 6" /><path d="M19 6l-1 14a2 2 0 01-2 2H8a2 2 0 01-2-2L5 6" /></svg>
                          </button>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </Layout>
  );
}
